static int ensure_capacity(string_builder_t* sb, size_t additional) {
    size_t required = sb->length + additional + 1;
    if (required <= sb->capacity) return 1;
    size_t new_cap = sb->capacity * 2;
    while (new_cap < required) new_cap *= 2;
    char* new_buf = realloc(sb->buffer, new_cap);
    if (!new_buf) return 0;
    sb->buffer = new_buf;
    sb->capacity = new_cap;
    return 1;
}

#include <stdarg.h>
#include <stdio.h>

int sb_append_fmt(string_builder_t* sb, const char* fmt, ...) {
    va_list args;
    va_start(args, fmt);
    int needed = vsnprintf(NULL, 0, fmt, args);
    va_end(args);
    if (needed < 0) return -1;
    if (!ensure_capacity(sb, needed)) return -1;
    va_start(args, fmt);
    vsnprintf(sb->buffer + sb->length, needed + 1, fmt, args);
    va_end(args);
    sb->length += needed;
    return needed;
}
